  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { sortable } from '@patternfly/react-table';
  4	import {
  5	  Alert,
  6	  AlertGroup,
  7	  Pagination,
  8	  EmptyState,
  9	  EmptyStateIcon,
 10	  EmptyStateBody,
 11	  Title,
 12	  ToolbarItem,
 13	  ToolbarGroup,
 14	  Select,
 15	  MenuToggle,
 16	  InputGroup,
 17	  TextInput,
 18	  MenuToggleElement,
 19	  SelectOption,
 20	  Toolbar,
 21	  ToolbarContent,
 22	} from '@patternfly/react-core';
 23	import {
 24	  K8sResourceCommon,
 25	  ResourceLink,
 26	  useK8sWatchResources,
 27	  VirtualizedTable,
 28	  Timestamp,
 29	  RowProps,
 30	  TableColumn,
 31	  WatchK8sResource,
 32	  ListPageBody,
 33	  TableData,
 34	} from '@openshift-console/dynamic-plugin-sdk';
 35	import { SearchIcon } from '@patternfly/react-icons';
 36	import { getStatusLabel } from '../utils/statusLabel';
 37	import DropdownWithKebab from './DropdownWithKebab';
 38	import useAccessReviews from '../utils/resourceRBAC';
 39	import { getResourceNameFromKind } from '../utils/getModelFromResource';
 40	
 41	type ResourceListProps = {
 42	  resources: Array<{
 43	    group: string;
 44	    version: string;
 45	    kind: string;
 46	  }>;
 47	  namespace?: string;
 48	  emtpyResourceName?: string;
 49	  paginationLimit?: number;
 50	  columns?: TableColumn<K8sResourceCommon>[];
 51	  renderers?: Record<
 52	    string,
 53	    (
 54	      column: TableColumn<K8sResourceCommon>,
 55	      resource: K8sResourceCommon,
 56	      activeColumnIDs: Set<string>,
 57	    ) => React.ReactNode
 58	  >;
 59	};
 60	
 61	const ResourceList: React.FC<ResourceListProps> = ({
 62	  resources,
 63	  namespace = '#ALL_NS#',
 64	  paginationLimit = 10,
 65	  columns,
 66	  renderers,
 67	  emtpyResourceName = 'Policies',
 68	}) => {
 69	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 70	
 71	  const accessResources = resources.map((r) => ({
 72	    ...r,
 73	    kind: getResourceNameFromKind(r.kind),
 74	  }));
 75	
 76	  const { userRBAC } = useAccessReviews(accessResources);
 77	
 78	  const resourceKinds = [
 79	    'AuthPolicy',
 80	    'RateLimitPolicy',
 81	    'DNSPolicy',
 82	    'TLSPolicy',
 83	    'Gateway',
 84	    'HTTPRoute',
 85	  ];
 86	
 87	  const resourceMappings = resourceKinds.map((kind) => ({
 88	    key: `${getResourceNameFromKind(kind)}-list`,
 89	    group: 'kuadrant.io',
 90	    version: 'v1',
 91	    kind,
 92	  }));
 93	
 94	  // filter out resources that the user doesn't have permission to list
 95	  const filteredResources = resources.filter((resource) => {
 96	    const mapping = resourceMappings.find((m) => m.kind === resource.kind);
 97	    const allowed = mapping ? userRBAC[mapping.key] : false;
 98	    return allowed;
 99	  });
100	
101	  const resourceDescriptors: { [key: string]: WatchK8sResource } = filteredResources.reduce(
102	    (acc, resource, index) => {
103	      const key = `${resource.group}-${resource.version}-${resource.kind}-${index}`;
104	      acc[key] = {
105	        groupVersionKind: {
106	          group: resource.group,
107	          version: resource.version,
108	          kind: resource.kind,
109	        },
110	        namespace: namespace === '#ALL_NS#' ? undefined : namespace,
111	        isList: true,
112	      };
113	      return acc;
114	    },
115	    {} as { [key: string]: WatchK8sResource },
116	  );
117	
118	  const watchedResources = useK8sWatchResources<{ [key: string]: K8sResourceCommon[] }>(
119	    resourceDescriptors,
120	  );
121	
122	  const allData = React.useMemo(
123	    () =>
124	      Object.values(watchedResources).flatMap((res) =>
125	        res.loaded && !res.loadError ? (res.data as K8sResourceCommon[]) : [],
126	      ),
127	    [watchedResources],
128	  );
129	
130	  const allLoaded = Object.values(watchedResources).every((res) => res.loaded);
131	
132	  const loadErrors = Object.values(watchedResources)
133	    .filter((res) => res.loadError)
134	    .map((res) => res.loadError);
135	  const combinedLoadError =
136	    loadErrors.length > 0 ? new Error(loadErrors.map((err) => err.message).join('; ')) : null;
137	
138	  // Implement local filter state
139	  const [filters, setFilters] = React.useState<string>('');
140	  const [isOpen, setIsOpen] = React.useState(false);
141	  const [filterSelected, setFilterSelected] = React.useState('Name');
142	  const [filteredData, setFilteredData] = React.useState<K8sResourceCommon[]>([]);
143	
144	  const onToggleClick = () => setIsOpen(!isOpen);
145	
146	  const onFilterSelect = (
147	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
148	    selection: string,
149	  ) => {
150	    setFilterSelected(selection);
151	    setIsOpen(false);
152	  };
153	
154	  React.useEffect(() => {
155	    let data = allData;
156	    if (filters) {
157	      const filterValue = filters.toLowerCase();
158	      data = data.filter((item) => {
159	        if (filterSelected === 'Name') {
160	          return item.metadata.name.toLowerCase().includes(filterValue);
161	        } else if (filterSelected === 'Namespace') {
162	          return item.metadata.namespace?.toLowerCase().includes(filterValue);
163	        } else if (filterSelected === 'Type') {
164	          return item.kind.toLowerCase().includes(filterValue);
165	        }
166	        return true;
167	      });
168	    }
169	    setFilteredData(data);
170	  }, [allData, filters, filterSelected]);
171	
172	  const defaultColumns: TableColumn<K8sResourceCommon>[] = [
173	    {
174	      title: t('plugin__kuadrant-console-plugin~Name'),
175	      id: 'name',
176	      sort: 'metadata.name',
177	      transforms: [sortable],
178	    },
179	    {
180	      title: t('plugin__kuadrant-console-plugin~Type'),
181	      id: 'type',
182	      sort: 'kind',
183	      transforms: [sortable],
184	    },
185	    {
186	      title: t('plugin__kuadrant-console-plugin~Namespace'),
187	      id: 'namespace',
188	      sort: 'metadata.namespace',
189	      transforms: [sortable],
190	    },
191	    {
192	      title: t('plugin__kuadrant-console-plugin~Status'),
193	      id: 'Status',
194	    },
195	    {
196	      title: t('plugin__kuadrant-console-plugin~Created'),
197	      id: 'Created',
198	      sort: 'metadata.creationTimestamp',
199	      transforms: [sortable],
200	    },
201	    {
202	      title: '', // No title for the kebab column
203	      id: 'kebab',
204	      props: { className: 'pf-v6-c-table__action' },
205	    },
206	  ];
207	
208	  const usedColumns = columns || defaultColumns;
209	
210	  const [currentPage, setCurrentPage] = React.useState<number>(1);
211	  const [perPage, setPerPage] = React.useState<number>(paginationLimit);
212	
213	  const startIndex = (currentPage - 1) * perPage;
214	  const endIndex = startIndex + perPage;
215	  const paginatedData = filteredData.slice(startIndex, endIndex);
216	
217	  const onSetPage = (
218	    _event: React.MouseEvent | React.KeyboardEvent | MouseEvent,
219	    pageNumber: number,
220	  ) => {
221	    setCurrentPage(pageNumber);
222	  };
223	
224	  const onPerPageSelect = (
225	    _event: React.MouseEvent | React.KeyboardEvent | MouseEvent,
226	    perPageNumber: number,
227	  ) => {
228	    setPerPage(perPageNumber);
229	    setCurrentPage(1);
230	  };
231	
232	  const handleFilterChange = (value: string) => {
233	    setCurrentPage(1);
234	    setFilters(value);
235	  };
236	
237	  const ResourceRow: React.FC<RowProps<K8sResourceCommon>> = ({ obj, activeColumnIDs }) => {
238	    const { apiVersion, kind } = obj;
239	    const [group, version] = apiVersion.includes('/') ? apiVersion.split('/') : ['', apiVersion];
240	
241	    return (
242	      <>
243	        {usedColumns.map((column) => {
244	          if (renderers && renderers[column.id]) {
245	            return renderers[column.id](column, obj, activeColumnIDs);
246	          } else {
247	            switch (column.id) {
248	              case 'name':
249	                return (
250	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
251	                    <ResourceLink
252	                      groupVersionKind={{ group, version, kind }}
253	                      name={obj.metadata.name}
254	                      namespace={obj.metadata.namespace}
255	                    />
256	                  </TableData>
257	                );
258	              case 'type':
259	                return (
260	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
261	                    {kind}
262	                  </TableData>
263	                );
264	              case 'namespace':
265	                return (
266	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
267	                    {obj.metadata.namespace ? (
268	                      <ResourceLink
269	                        groupVersionKind={{ version: 'v1', kind: 'Namespace' }}
270	                        name={obj.metadata.namespace}
271	                      />
272	                    ) : (
273	                      '-'
274	                    )}
275	                  </TableData>
276	                );
277	              case 'Status':
278	                return (
279	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
280	                    {getStatusLabel(obj)}
281	                  </TableData>
282	                );
283	              case 'Created':
284	                return (
285	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
286	                    <Timestamp timestamp={obj.metadata.creationTimestamp} />
287	                  </TableData>
288	                );
289	              case 'kebab':
290	                return (
291	                  <TableData
292	                    key={column.id}
293	                    id={column.id}
294	                    activeColumnIDs={activeColumnIDs}
295	                    className="pf-v6-c-table__action"
296	                  >
297	                    <DropdownWithKebab obj={obj} />
298	                  </TableData>
299	                );
300	              default:
301	                return null;
302	            }
303	          }
304	        })}
305	      </>
306	    );
307	  };
308	
309	  return (
310	    <>
311	      {combinedLoadError && (
312	        <AlertGroup>
313	          <Alert title="Error loading resources" variant="danger" isInline>
314	            {combinedLoadError.message}
315	          </Alert>
316	        </AlertGroup>
317	      )}
318	      <div className="kuadrant-policy-list-body">
319	        <ListPageBody>
320	          <Toolbar>
321	            <ToolbarContent>
322	              <ToolbarGroup variant="filter-group">
323	                <ToolbarItem>
324	                  <Select
325	                    toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
326	                      <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen}>
327	                        {filterSelected}
328	                      </MenuToggle>
329	                    )}
330	                    onSelect={onFilterSelect}
331	                    onOpenChange={setIsOpen}
332	                    isOpen={isOpen}
333	                  >
334	                    {['Name', 'Namespace', 'Type'].map((option, index) => (
335	                      <SelectOption key={index} value={option}>
336	                        {option}
337	                      </SelectOption>
338	                    ))}
339	                  </Select>
340	                </ToolbarItem>
341	
342	                <ToolbarItem>
343	                  <InputGroup className="pf-v6-c-input-group co-filter-group">
344	                    <TextInput
345	                      type="text"
346	                      placeholder={t('Search by {{filterValue}}...', {
347	                        filterValue: filterSelected.toLowerCase(),
348	                      })}
349	                      onChange={(_event, value) => handleFilterChange(value)}
350	                      className="pf-v6-c-form-control co-text-filter-with-icon"
351	                      aria-label="Resource search"
352	                    />
353	                  </InputGroup>
354	                </ToolbarItem>
355	              </ToolbarGroup>
356	            </ToolbarContent>
357	          </Toolbar>
358	          {paginatedData.length === 0 && allLoaded ? (
359	            <EmptyState>
360	              <EmptyStateIcon icon={SearchIcon} />
361	              <Title headingLevel="h4" size="lg">
362	                {t('No')} {emtpyResourceName} {t('found')}
363	              </Title>
364	              <EmptyStateBody>
365	                {t('There are no')} {emtpyResourceName} {t('to display - please create some.')}
366	              </EmptyStateBody>
367	            </EmptyState>
368	          ) : (
369	            <VirtualizedTable<K8sResourceCommon>
370	              data={paginatedData}
371	              unfilteredData={filteredData}
372	              loaded={allLoaded}
373	              loadError={combinedLoadError}
374	              columns={usedColumns}
375	              Row={ResourceRow}
376	            />
377	          )}
378	
379	          {filteredData.length > 0 && (
380	            <div className="kuadrant-pagination-left">
381	              <Pagination
382	                itemCount={filteredData.length}
383	                perPage={perPage}
384	                page={currentPage}
385	                onSetPage={onSetPage}
386	                onPerPageSelect={onPerPageSelect}
387	                variant="bottom"
388	                perPageOptions={[
389	                  { title: '5', value: 5 },
390	                  { title: '10', value: 10 },
391	                  { title: '20', value: 20 },
392	                ]}
393	              />
394	            </div>
395	          )}
396	        </ListPageBody>
397	      </div>
398	    </>
399	  );
400	};
401	
402	export default ResourceList;

