 21	import {
 22	  K8sResourceCommon,
 23	  ResourceLink,
 24	  useK8sWatchResources,
 25	  VirtualizedTable,
 26	  Timestamp,
 27	  RowProps,
 28	  TableColumn,
 29	  WatchK8sResource,
 30	  ListPageBody,
 31	  TableData,
 32	} from '@openshift-console/dynamic-plugin-sdk';
 33	import { SearchIcon } from '@patternfly/react-icons';
 34	import { getStatusLabel } from '../utils/statusLabel';
 35	import DropdownWithKebab from './DropdownWithKebab';
 36	import useAccessReviews from '../utils/resourceRBAC';
 37	import { getResourceNameFromKind } from '../utils/getModelFromResource';
 38	
 39	type ResourceListProps = {
 40	  resources: Array<{
 41	    group: string;
 42	    version: string;
 43	    kind: string;
 44	  }>;
 45	  namespace?: string;
 46	  emtpyResourceName?: string;
 47	  paginationLimit?: number;
 48	  columns?: TableColumn<K8sResourceCommon>[];
 49	  renderers?: Record<
 50	    string,
 51	    (
 52	      column: TableColumn<K8sResourceCommon>,
 53	      resource: K8sResourceCommon,
 54	      activeColumnIDs: Set<string>,
 55	    ) => React.ReactNode
 56	  >;
 57	};
 58	
 59	const ResourceList: React.FC<ResourceListProps> = ({
 60	  resources,
 61	  namespace = '#ALL_NS#',
 62	  paginationLimit = 10,
 63	  columns,
 64	  renderers,
 65	  emtpyResourceName = 'Policies',
 66	}) => {
 67	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 68	
 69	  const accessResources = resources.map((r) => ({
 70	    ...r,
 71	    kind: getResourceNameFromKind(r.kind),
 72	  }));
 73	
 74	  const { userRBAC } = useAccessReviews(accessResources);
 75	
 76	  const resourceKinds = [
 77	    'AuthPolicy',
 78	    'RateLimitPolicy',
 79	    'DNSPolicy',
 80	    'TLSPolicy',
 81	    'Gateway',
 82	    'HTTPRoute',
 83	  ];
 84	
 85	  const resourceMappings = resourceKinds.map((kind) => ({
 86	    key: `${getResourceNameFromKind(kind)}-list`,
 87	    group: 'kuadrant.io',
 88	    version: 'v1',
 89	    kind,
 90	  }));
 91	
 92	  // filter out resources that the user doesn't have permission to list
 93	  const filteredResources = resources.filter((resource) => {
 94	    const mapping = resourceMappings.find((m) => m.kind === resource.kind);
 95	    const allowed = mapping ? userRBAC[mapping.key] : false;
 96	    return allowed;
 97	  });
 98	
 99	  const resourceDescriptors: { [key: string]: WatchK8sResource } = filteredResources.reduce(
100	    (acc, resource, index) => {
101	      const key = `${resource.group}-${resource.version}-${resource.kind}-${index}`;
102	      acc[key] = {
103	        groupVersionKind: {
104	          group: resource.group,
105	          version: resource.version,
106	          kind: resource.kind,
107	        },
108	        namespace: namespace === '#ALL_NS#' ? undefined : namespace,
109	        isList: true,
110	      };
111	      return acc;
112	    },
113	    {} as { [key: string]: WatchK8sResource },
114	  );
115	
116	  const watchedResources = useK8sWatchResources<{ [key: string]: K8sResourceCommon[] }>(
117	    resourceDescriptors,
118	  );
119	
120	  const allData = React.useMemo(
121	    () =>
122	      Object.values(watchedResources).flatMap((res) =>
123	        res.loaded && !res.loadError ? (res.data as K8sResourceCommon[]) : [],
124	      ),
125	    [watchedResources],
126	  );
127	
128	  const allLoaded = Object.values(watchedResources).every((res) => res.loaded);
129	
130	  const loadErrors = Object.values(watchedResources)
131	    .filter((res) => res.loadError)
132	    .map((res) => res.loadError);
133	  const combinedLoadError =
134	    loadErrors.length > 0 ? new Error(loadErrors.map((err) => err.message).join('; ')) : null;
135	
136	  // Implement local filter state
137	  const [filters, setFilters] = React.useState<string>('');
138	  const [isOpen, setIsOpen] = React.useState(false);
139	  const [filterSelected, setFilterSelected] = React.useState('Name');
140	  const [filteredData, setFilteredData] = React.useState<K8sResourceCommon[]>([]);
141	
142	  const onToggleClick = () => setIsOpen(!isOpen);
143	
144	  const onFilterSelect = (
145	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
146	    selection: string,
147	  ) => {
148	    setFilterSelected(selection);
149	    setIsOpen(false);
150	  };
151	
152	  React.useEffect(() => {
153	    let data = allData;
154	    if (filters) {
155	      const filterValue = filters.toLowerCase();
156	      data = data.filter((item) => {
157	        if (filterSelected === 'Name') {
158	          return item.metadata.name.toLowerCase().includes(filterValue);
159	        } else if (filterSelected === 'Namespace') {
160	          return item.metadata.namespace?.toLowerCase().includes(filterValue);
161	        } else if (filterSelected === 'Type') {
162	          return item.kind.toLowerCase().includes(filterValue);
163	        }
164	        return true;
165	      });
166	    }
167	    setFilteredData(data);
168	  }, [allData, filters, filterSelected]);
169	
170	  const defaultColumns: TableColumn<K8sResourceCommon>[] = [
171	    {
172	      title: t('plugin__kuadrant-console-plugin~Name'),
173	      id: 'name',
174	      sort: 'metadata.name',
175	      transforms: [sortable],
176	    },
177	    {
178	      title: t('plugin__kuadrant-console-plugin~Type'),
179	      id: 'type',
180	      sort: 'kind',
181	      transforms: [sortable],
182	    },
183	    {
184	      title: t('plugin__kuadrant-console-plugin~Namespace'),
185	      id: 'namespace',
186	      sort: 'metadata.namespace',
187	      transforms: [sortable],
188	    },
189	    {
190	      title: t('plugin__kuadrant-console-plugin~Status'),
191	      id: 'Status',
192	    },
193	    {
194	      title: t('plugin__kuadrant-console-plugin~Created'),
195	      id: 'Created',
196	      sort: 'metadata.creationTimestamp',
197	      transforms: [sortable],
198	    },
199	    {
200	      title: '', // No title for the kebab column
201	      id: 'kebab',
202	      props: { className: 'pf-v6-c-table__action' },
203	    },
204	  ];
205	
206	  const usedColumns = columns || defaultColumns;
207	
208	  const [currentPage, setCurrentPage] = React.useState<number>(1);
209	  const [perPage, setPerPage] = React.useState<number>(paginationLimit);
210	
211	  const startIndex = (currentPage - 1) * perPage;
212	  const endIndex = startIndex + perPage;
213	  const paginatedData = filteredData.slice(startIndex, endIndex);
214	
215	  const onSetPage = (
216	    _event: React.MouseEvent | React.KeyboardEvent | MouseEvent,
217	    pageNumber: number,
218	  ) => {
219	    setCurrentPage(pageNumber);
220	  };
221	
222	  const onPerPageSelect = (
223	    _event: React.MouseEvent | React.KeyboardEvent | MouseEvent,
224	    perPageNumber: number,
225	  ) => {
226	    setPerPage(perPageNumber);
227	    setCurrentPage(1);
228	  };
229	
230	  const handleFilterChange = (value: string) => {
231	    setCurrentPage(1);
232	    setFilters(value);
233	  };
234	
235	  const ResourceRow: React.FC<RowProps<K8sResourceCommon>> = ({ obj, activeColumnIDs }) => {
236	    const { apiVersion, kind } = obj;
237	    const [group, version] = apiVersion.includes('/') ? apiVersion.split('/') : ['', apiVersion];
238	
239	    return (
240	      <>
241	        {usedColumns.map((column) => {
242	          if (renderers && renderers[column.id]) {
243	            return renderers[column.id](column, obj, activeColumnIDs);
244	          } else {
245	            switch (column.id) {
246	              case 'name':
247	                return (
248	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
249	                    <ResourceLink
250	                      groupVersionKind={{ group, version, kind }}
251	                      name={obj.metadata.name}
252	                      namespace={obj.metadata.namespace}
253	                    />
254	                  </TableData>
255	                );
256	              case 'type':
257	                return (
258	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
259	                    {kind}
260	                  </TableData>
261	                );
262	              case 'namespace':
263	                return (
264	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
265	                    {obj.metadata.namespace ? (
266	                      <ResourceLink
267	                        groupVersionKind={{ version: 'v1', kind: 'Namespace' }}
268	                        name={obj.metadata.namespace}
269	                      />
270	                    ) : (
271	                      '-'
272	                    )}
273	                  </TableData>
274	                );
275	              case 'Status':
276	                return (
277	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
278	                    {getStatusLabel(obj)}
279	                  </TableData>
280	                );
281	              case 'Created':
282	                return (
283	                  <TableData key={column.id} id={column.id} activeColumnIDs={activeColumnIDs}>
284	                    <Timestamp timestamp={obj.metadata.creationTimestamp} />
285	                  </TableData>
286	                );
287	              case 'kebab':
288	                return (
289	                  <TableData
290	                    key={column.id}
291	                    id={column.id}
292	                    activeColumnIDs={activeColumnIDs}
293	                    className="pf-v6-c-table__action"
294	                  >
295	                    <DropdownWithKebab obj={obj} />
296	                  </TableData>
297	                );
298	              default:
299	                return null;
300	            }
301	          }
302	        })}
303	      </>
304	    );
305	  };
306	
307	  return (
308	    <>
309	      {combinedLoadError && (
310	        <AlertGroup>
311	          <Alert title="Error loading resources" variant="danger" isInline>
312	            {combinedLoadError.message}
313	          </Alert>
314	        </AlertGroup>
315	      )}
316	      <div className="kuadrant-policy-list-body">
317	        <ListPageBody>
318	          <Toolbar>
319	            <ToolbarContent>
320	              <ToolbarGroup variant="filter-group">
321	                <ToolbarItem>
322	                  <Select
323	                    toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
324	                      <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen}>
325	                        {filterSelected}
326	                      </MenuToggle>
327	                    )}
328	                    onSelect={onFilterSelect}
329	                    onOpenChange={setIsOpen}
330	                    isOpen={isOpen}
331	                  >
332	                    {['Name', 'Namespace', 'Type'].map((option, index) => (
333	                      <SelectOption key={index} value={option}>
334	                        {option}
335	                      </SelectOption>
336	                    ))}
337	                  </Select>
338	                </ToolbarItem>
339	
340	                <ToolbarItem>
341	                  <InputGroup className="pf-v6-c-input-group co-filter-group">
342	                    <TextInput
343	                      type="text"
344	                      placeholder={t('Search by {{filterValue}}...', {
345	                        filterValue: filterSelected.toLowerCase(),
346	                      })}
347	                      onChange={(_event, value) => handleFilterChange(value)}
348	                      className="pf-v6-c-form-control co-text-filter-with-icon"
349	                      aria-label="Resource search"
350	                    />
351	                  </InputGroup>
352	                </ToolbarItem>
353	              </ToolbarGroup>
354	            </ToolbarContent>
355	          </Toolbar>
356	          {paginatedData.length === 0 && allLoaded ? (
357	            <EmptyState icon={SearchIcon} headingLevel="h4" titleText={`${t('No')} ${emtpyResourceName} ${t('found')}`}>
358	              <EmptyStateBody>
359	                {t('There are no')} {emtpyResourceName} {t('to display - please create some.')}
360	              </EmptyStateBody>
361	            </EmptyState>
362	          ) : (
363	            <VirtualizedTable<K8sResourceCommon>
364	              data={paginatedData}
365	              unfilteredData={filteredData}
366	              loaded={allLoaded}
367	              loadError={combinedLoadError}
368	              columns={usedColumns}
369	              Row={ResourceRow}
370	            />
371	          )}
372	
373	          {filteredData.length > 0 && (
374	            <div className="kuadrant-pagination-left">
375	              <Pagination
376	                itemCount={filteredData.length}
377	                perPage={perPage}
378	                page={currentPage}
379	                onSetPage={onSetPage}
380	                onPerPageSelect={onPerPageSelect}
381	                variant="bottom"
382	                perPageOptions={[
383	                  { title: '5', value: 5 },
384	                  { title: '10', value: 10 },
385	                  { title: '20', value: 20 },
386	                ]}
387	              />
388	            </div>
389	          )}
390	        </ListPageBody>
391	      </div>
392	    </>
393	  );
394	};
395	
396	export default ResourceList;

