370	              loadError={combinedLoadError}
371	              columns={usedColumns}
372	              Row={ResourceRow}
373	            />
374	          )}
375	
376	          {filteredData.length > 0 && (
377	            <div className="kuadrant-pagination-left">
378	              <Pagination
379	                itemCount={filteredData.length}
380	                perPage={perPage}
381	                page={currentPage}
382	                onSetPage={onSetPage}
383	                onPerPageSelect={onPerPageSelect}
384	                variant="bottom"
385	                perPageOptions={[
386	                  { title: '5', value: 5 },
387	                  { title: '10', value: 10 },
388	                  { title: '20', value: 20 },
389	                ]}
390	              />
391	            </div>
392	          )}
393	        </ListPageBody>
394	      </div>
395	    </>
396	  );
397	};
398	
399	export default ResourceList;

